esqlQuery.esql:
// Alert when a Zabbix proxy goes offline or has an outdated/unsupported version.
// Offline proxies stop collecting data from monitored hosts.
FROM metrics-zabbix.proxy_health-*
| WHERE zabbix.proxy.state == "offline" OR zabbix.proxy.compatibility IN ("outdated", "unsupported")
| STATS occurrences = COUNT(*) BY zabbix.proxy.name, zabbix.proxy.state, zabbix.proxy.compatibility
| WHERE occurrences >= 1
